import { ethers } from "ethers";

const factoryAddress = "0x9B137463d4E7986D7f535f9B79e28b4EF1938E9b";
const number = 123456;

// 1: salt = keccak256(abi.encodePacked(_no))
const salt = ethers.solidityPackedKeccak256(["uint256"], [number]);

// Step 2: hash of the initCode (bytecode + constructor args)
const initCode =
  "" +
  ethers.AbiCoder.defaultAbiCoder().encode(["uint256"], [number]).slice(2);
const initCodeHash = ethers.keccak256(initCode);

const predicted = ethers.getCreate2Address(factoryAddress, salt, initCodeHash);

console.log("Predicted:", predicted);
